import{H as e,V as t,et as n,j as r}from"./chunks/framework.C_EfTa_6.js";var i=JSON.parse(`{"title":"部署","description":"","frontmatter":{"title":"部署","order":100},"headers":[],"relativePath":"ai/compute/deploy/index.md","filePath":"ai/compute/deploy/index.md"}`),a={name:`ai/compute/deploy/index.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="ai-模型部署" tabindex="-1">AI 模型部署 <a class="header-anchor" href="#ai-模型部署" aria-label="Permalink to “AI 模型部署”">​</a></h1><p>将 AI 模型高效地运行在实际硬件上，涉及从 GPU 选型、量化压缩、多卡并行到推理加速和服务部署的完整链路。每一层决策都直接影响模型能否跑起来、跑多快、服务多少用户。</p><p>从零开始的流程：本文下述章节覆盖选模型→选工具→参数调优→实战配置。深入各环节：<a href="./hardware">GPU 硬件选型</a> → <a href="./quantization">模型量化</a> → <a href="./multi-gpu">多卡推理</a> → <a href="./optimization">推理优化</a> → <a href="./serving">服务部署</a>。生产运维：<a href="./llmops">LLMOps</a> 负责评估、监控和成本控制。</p><p>推理引擎本身的架构和使用见<a href="/ai/app/engine/">推理引擎</a>章节。</p><p><strong>如何把一个 AI 模型跑起来？</strong></p><p>假设你已经有了硬件——无论是一张 RTX 4060 还是一台二手 EPYC + 多路 GPU 服务器。接下来的问题是：下载哪个模型、用什么工具跑、参数怎么调。本文是从零到跑起一个对话模型的完整流程。</p><p>量化原理和格式选型见<a href="./quantization">模型量化</a>，多 GPU 策略见<a href="./multi-gpu">多卡推理</a>，推理加速技术见<a href="./optimization">推理优化</a>，GPU 硬件选型见 <a href="./hardware">GPU 硬件</a>。</p><h2 id="选模型" tabindex="-1">选模型 <a class="header-anchor" href="#选模型" aria-label="Permalink to “选模型”">​</a></h2><p>模型选择取决于三个硬约束：显存容量、使用场景、质量要求。FP16 下每 1B 参数约需 2GB 显存，INT4 量化（Q4_K_M）压缩到约原来的 1/4：</p><ul><li>8GB 显存：INT4 下能跑 7-8B 模型（Llama-3-8B ≈ 5GB）</li><li>24GB 显存：INT4 下能跑 32-34B 模型（Qwen2.5-32B ≈ 19GB）</li><li>48GB 显存：INT4 下能跑 70B 模型（Llama-3-70B ≈ 38GB）</li></ul><p>当前推荐模型（2026 年 7 月）：</p><table tabindex="0"><thead><tr><th>模型</th><th>参数量</th><th>显存需求 (Q4_K_M)</th><th>适合场景</th></tr></thead><tbody><tr><td>Qwen3.6-8B</td><td>8B</td><td>~5 GB</td><td>中文对话、轻量 Agent</td></tr><tr><td>Gemma-3-12B</td><td>12B</td><td>~8 GB</td><td>多语言对话、长上下文 (32K)</td></tr><tr><td>Qwen3.6-32B</td><td>32B</td><td>~19 GB</td><td>代码生成、复杂推理</td></tr><tr><td>DeepSeek-V3.1</td><td>685B (37B active)</td><td>~24 GB</td><td>MoE 旗舰，综合能力最强</td></tr><tr><td>Llama-4-70B</td><td>70B</td><td>~38 GB</td><td>需多 GPU 或高端卡</td></tr></tbody></table><p>Qwen3.6 是目前开源中文能力最强的系列。Gemma 3 在同参数级别中长上下文表现突出。DeepSeek-V3.1 的 MoE 架构每次只激活约 37B 参数，综合能力对标 GPT-5 且支持 128K 上下文。</p><h2 id="选工具" tabindex="-1">选工具 <a class="header-anchor" href="#选工具" aria-label="Permalink to “选工具”">​</a></h2><p>三条路径，选哪条取决于技术深度和使用场景。</p><p>Ollama 路线（5 分钟跑起来）：<code>ollama run qwen2.5:14b</code> 一条命令下载并启动模型。自动管理 GGUF 版本、GPU 层数、KV Cache 类型。适合非技术用户、快速测试和日常对话。通过 Modelfile 定制 system prompt 和参数。</p><p>llama.cpp 路线（精细硬件控制）：手动指定 GPU 层数（<code>-ngl</code>）、KV Cache 量化（<code>--cache-type-k</code>）、上下文长度（<code>--ctx-size</code>）。CPU+GPU 混合推理突破显存上限。适合有动手能力、追求硬件控制的用户。</p><p>SGLang / vLLM 路线（生产环境、高频调用）：支持连续批处理，多请求并发处理。SGLang 在单 GPU 多轮对话场景的 RadixAttention 对 RAG 有额外加速，部署更简单。vLLM 对多 GPU 分布式推理支持更成熟。命令行一行启动，兼容 OpenAI API。</p><p>引擎的详细对比见<a href="/ai/app/engine/">推理引擎</a>，工具生态和启动命令参考见<a href="./eco">部署工具</a>。</p><h2 id="参数调优" tabindex="-1">参数调优 <a class="header-anchor" href="#参数调优" aria-label="Permalink to “参数调优”">​</a></h2><p>Temperature（0-2，常用 0.7-1.0）控制随机性：代码生成设 &lt; 0.3，创意写作设 0.8-1.0。Top-p（0-1，常用 0.9）从累积概率达到 p 的最小词集合中采样。上下文长度每增加一个 token 都消耗 KV Cache 显存——8K vs 32K 可能差出 4-6GB。Repeat penalty（1.1-1.2）抑制模型重复输出。</p><h2 id="不同硬件的实战配置" tabindex="-1">不同硬件的实战配置 <a class="header-anchor" href="#不同硬件的实战配置" aria-label="Permalink to “不同硬件的实战配置”">​</a></h2><h3 id="消费级入门-rtx-4060-8gb" tabindex="-1">消费级入门（RTX 4060 8GB） <a class="header-anchor" href="#消费级入门-rtx-4060-8gb" aria-label="Permalink to “消费级入门（RTX 4060 8GB）”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen2.5:7b-q4_K_M</span></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 或 llama.cpp:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./llama-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen2.5-7b-Q4_K_M.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ctx-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4096</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ngl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 999</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --temp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.7</span></span></code></pre></div><p>能做的事：日常对话、翻译、简单文档问答。不能做的事：32K+ 长文档分析、复杂多步推理。</p><h3 id="消费级中高端-rtx-4090-24gb" tabindex="-1">消费级中高端（RTX 4090 24GB） <a class="header-anchor" href="#消费级中高端-rtx-4090-24gb" aria-label="Permalink to “消费级中高端（RTX 4090 24GB）”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sglang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Qwen/Qwen2.5-32B-Instruct-AWQ</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-total-tokens</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8192</span></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 或 Ollama:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ollama</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen2.5:32b-q4_K_M</span></span></code></pre></div><p>AWQ 量化后 32B 模型约 19GB，剩余 5GB 给 KV Cache 支持 8K 上下文。能做代码生成和 review、复杂 RAG 问答、Agent 工作流。</p><h3 id="本地服务器-epyc-多-gpu" tabindex="-1">本地服务器（EPYC + 多 GPU） <a class="header-anchor" href="#本地服务器-epyc-多-gpu" aria-label="Permalink to “本地服务器（EPYC + 多 GPU）”">​</a></h3><p>单路 EPYC Rome 64 核 + 128GB RDIMM + 2×RTX 4090 的典型配置：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sglang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Qwen/Qwen2.5-72B-Instruct-AWQ</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-total-tokens</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16384</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span></code></pre></div><p>TP=2 将模型拆分到两张 GPU，AWQ 量化后 72B 约 42GB。NVLink 桥接下通信延迟约 2-5 μs，PCIe 直连下约 15-30 μs——每 token 生成时间 PCIe 比 NVLink 慢约 5-10ms。多 GPU 并行策略的选择见<a href="./multi-gpu">多卡推理</a>。</p><h2 id="验证跑通" tabindex="-1">验证跑通 <a class="header-anchor" href="#验证跑通" aria-label="Permalink to “验证跑通”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8080/v1/chat/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;model&quot;:&quot;qwen2.5-32b&quot;,&quot;messages&quot;:[{&quot;role&quot;:&quot;user&quot;,&quot;content&quot;:&quot;1+1等于几？&quot;}]}&#39;</span></span></code></pre></div><p>返回 JSON 中有 <code>choices[0].message.content</code> 即为成功。LLM 服务启动后通常有 Chat Web UI 在 <code>http://localhost:8080</code>。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to “常见问题”">​</a></h2><p>模型下载慢：设置镜像 <code>export HF_ENDPOINT=https://hf-mirror.com</code>。GGUF 文件在 HuggingFace 上搜索模型名 + GGUF 即可。Ollama 会自动从加速源拉取。</p><p>OOM（显存不够）：降低模型精度（Q4_K_M → Q3_K_M）、缩短最大上下文长度（<code>--ctx-size 4096</code>）、减少 GPU 层数（<code>-ngl</code> 调小让更多层走 CPU 卸载）。</p><p>生成速度慢：检查是否全部层都在 GPU 上（Ollama 中 <code>ollama ps</code> 看 GPU 利用率，llama.cpp 中确认 <code>-ngl 999</code>）。CPU 卸载的每层会让速度掉 2-5 倍。投机解码可将 Decode 速度提升 1.5-2.5 倍，详见<a href="./optimization">推理优化</a>。</p><p>输出乱码或循环：调低 temperature（0.1-0.3）或调高 repeat_penalty（1.15-1.2）。Qwen 系列在 temperature 低于 0.5 时表现更好，Llama 系列适合 0.7-0.9。</p>`,40)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};